import osimport refrom config import DB_DIRclass ArticulLogic:    def __init__(self):        # Використовуємо set (множину) для миттєвого пошуку унікальних цін        self.occupied_prices = set()    def get_vendor_code(self, vendor_str):        """Витягує код вендора з рядка виду '[207] Pc.Lviv'"""        if not vendor_str: return "207"        match = re.search(r'\[(\d+)\]', vendor_str)        return match.group(1) if match else "207"    def load_local_data(self, code):        """Завантажує базу цін для конкретного вендора"""        db_path = os.path.join(DB_DIR, f"vendor_{code}.txt")        self.occupied_prices = set()                if os.path.exists(db_path):            try:                with open(db_path, 'r', encoding='utf-8', errors='ignore') as f:                    for line in f:                        # Очищаємо рядок від пробілів та спецсимволів                        clean_line = line.strip()                        if clean_line.isdigit():                             self.occupied_prices.add(int(clean_line))            except Exception as e:                print(f"Error loading database for vendor {code}: {e}")                        return len(self.occupied_prices)    def generate_articul(self, price_val, code):        """Генерує унікальний артикул, зменшуючи ціну на 1, поки вона не стане вільною"""        curr = int(price_val)        while curr in self.occupied_prices:            curr -= 1                self.occupied_prices.add(curr)        return f"{curr}_{code}", curr    def save_to_file(self, code):        """Зберігає список зайнятих цін у файл (від більшої до меншої)"""        os.makedirs(DB_DIR, exist_ok=True)        db_path = os.path.join(DB_DIR, f"vendor_{code}.txt")                try:            with open(db_path, 'w', encoding='utf-8') as f:                # Сортуємо для зручності читання файлу людиною                for p in sorted(list(self.occupied_prices), reverse=True):                    f.write(f"{p}\n")        except Exception as e:            print(f"Error saving file for vendor {code}: {e}")    def get_sorted_prices(self):        """Повертає список цін для відображення в 'Оці' (👁)"""        return sorted(list(self.occupied_prices), reverse=True)    def import_txt(self, file_path):        """        Зчитує ціни з будь-якого TXT і додає до поточної бази.        Шукає число на початку рядка, ігноруючи все інше.        """        added_count = 0        try:            if not os.path.exists(file_path):                return 0                            with open(file_path, 'r', encoding='utf-8', errors='ignore') as f:                for line in f:                    # Регулярний вираз шукає групу цифр на початку рядка                    match = re.search(r'^(\d+)', line.strip())                    if match:                        price = int(match.group(1))                        if price not in self.occupied_prices:                            self.occupied_prices.add(price)                            added_count += 1            return added_count        except Exception as e:            print(f"Error during import in logic.py: {e}")            return 0